package basics;

public class assingment1 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		
		//Assignment 1
		//o/p:- Factorial of 5 is 120
		//working:- 5=1*2*3*4*5=120
				
			//5=1*2*3*4*5
		
		
			int a=5,f=1;
			//i=5
							
			for (int i=1; i<=a; i++)
			{
				f=f*i; //factorial formula
			
			}
		    System.out.println(" Factorial of "+a+" is "+f);
		
	}

}
